import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import { copySudokuBoard, createSudokuBoard } from '@algorithm.ts/sudoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { getSudokuCreator } from '../util/creator'
import { runInstructs } from '../util/instruction'
import { checkCompleted, checkPlaying } from '../util/status'
import type { SudokuInstructionType } from './constant'

export interface ISudokuBoardCell {
  r: number
  c: number
}

export type ISudokuInstruction =
  | {
      type: SudokuInstructionType.ERASE
      payload: { r: number; c: number }
      timestamp: string // ISO string
    }
  | {
      type: SudokuInstructionType.HINT
      payload: { r: number; c: number }
      timestamp: string // ISO string
    }
  | {
      type: SudokuInstructionType.WRITE
      payload: { r: number; c: number; v: number }
      timestamp: string // ISO string
    }

export interface ISudokuState {
  /**
   * Sudoku size, sqrt of the number of rows or columns.
   */
  SUDOKU_SIZE_SQRT: 2 | 3 | 4
  /**
   * Game difficulty.
   */
  difficulty: number
  /**
   * Displayed radix.
   */
  radix: 10 | 16
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Total score.
   */
  score: number
  /**
   * Sudoku puzzle.
   */
  puzzle: Readonly<ISudokuBoard>
  /**
   * Solution of the puzzle.
   */
  solution: Readonly<ISudokuBoard>
  /**
   * Attempt on the puzzle.
   */
  attempt: Readonly<ISudokuBoard>
  /**
   * Player instructions.
   */
  instructions: ReadonlyArray<ISudokuInstruction>
  /**
   * Currently activated board cell.
   */
  activatedCell: Readonly<ISudokuBoardCell>
  /**
   * The coordinate of the board cell for hint.
   */
  hintCell: Readonly<ISudokuBoardCell> | null
  /**
   * Whether to display the solution of the quiz.
   */
  cheatVisible: boolean
  /**
   * Time spent in this game
   */
  usedTimeRef: {
    current: number
  }
  /**
   * Used to judge if the game has restarted.
   */
  gameTick: number
  /**
   * Times of attempt on the current game.
   */
  attemptTick: number
  /**
   * To retrigger the hint animation when the multiple times hint requests on a
   * same cell were fired.
   */
  hintTick: number
}

export type ISudokuData = ISudokuState

export const initSudokuState = (
  customizedData?: Partial<ISudokuData> | null,
  baseState: Readonly<ISudokuState> = defaultSudokuState,
): ISudokuState => {
  const {
    SUDOKU_SIZE_SQRT = baseState.SUDOKU_SIZE_SQRT,
    difficulty = baseState.difficulty,
    score = baseState.score,
    radix = baseState.radix,
    activatedCell = baseState.activatedCell,
    gameTick = baseState.gameTick,
    puzzle: _puzzle = baseState.puzzle,
    solution: _solution = baseState.solution,
    instructions = baseState.instructions.slice(),
    usedTimeRef = { current: baseState.usedTimeRef.current },
  } = { ...customizedData }

  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
  const { puzzle, solution } =
    _puzzle != null && _solution != null
      ? { puzzle: _puzzle!, solution: _solution! }
      : getSudokuCreator(SUDOKU_SIZE_SQRT).createSudoku(difficulty / 100)

  const attempt = createSudokuBoard(SUDOKU_SIZE)
  copySudokuBoard(puzzle, attempt as ISudokuBoard)
  runInstructs(attempt, instructions)

  const { r = -1, c = -1 } = activatedCell ?? {}
  const gameStatus: GameRunningStatus = checkCompleted(SUDOKU_SIZE, attempt, solution)
    ? GameRunningStatus.FINISHED
    : checkPlaying(SUDOKU_SIZE, attempt, puzzle)
    ? GameRunningStatus.PAUSED
    : GameRunningStatus.PENDING

  return {
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    gameStatus,
    score,
    attempt,
    instructions,
    puzzle,
    solution,
    activatedCell: { r, c },
    hintCell: null,
    cheatVisible: false,
    usedTimeRef,
    gameTick,
    attemptTick: 0,
    hintTick: 0,
  }
}

const defaultSudokuState: ISudokuState = {
  SUDOKU_SIZE_SQRT: 3,
  difficulty: 20,
  radix: 10,
  gameStatus: GameRunningStatus.PENDING,
  score: 0,
  puzzle: null as any,
  solution: null as any,
  attempt: null as any,
  instructions: [],
  activatedCell: { r: -1, c: -1 },
  hintCell: { r: -1, c: -1 },
  cheatVisible: false,
  usedTimeRef: { current: 0 },
  gameTick: 0,
  attemptTick: 0,
  hintTick: 0,
}
