import { createUseSelectableContext, pick } from '@kyokuya/core-util'
import { createPersistProvider } from '@kyokuya/react-storage'
import React from 'react'
import type { ISudokuAction } from './action'
import { sudokuReducer } from './reducer'
import type { ISudokuData, ISudokuState } from './state'
import { initSudokuState } from './state'

export interface ISudokuContext {
  state: ISudokuState
  dispatch: React.Dispatch<ISudokuAction>
}

const SudokuContextType = React.createContext<ISudokuContext>({
  state: initSudokuState(),
  dispatch: (): void => {
    throw new Error(`[SudokuContextType] dispatch is not available yet.`)
  },
})

export const SudokuContextProvider = createPersistProvider<
  ISudokuState,
  ISudokuAction,
  ISudokuData
>({
  ContextType: SudokuContextType,
  ContextName: 'SudokuContext',
  initState: initSudokuState,
  reducer: sudokuReducer,
  serialize: latestData =>
    pick(latestData, [
      'SUDOKU_SIZE_SQRT',
      'difficulty',
      'radix',
      'score',
      'puzzle',
      'solution',
      'instructions',
      'activatedCell',
      'usedTimeRef',
    ]),
})

export const useSudokuContext = createUseSelectableContext(SudokuContextType)
