import PropTypes from 'prop-types'
import React from 'react'
import type { ISudokuState } from './context'
import { SudokuContextProvider } from './context'
import { SudokuGameMain } from './SudokuGameMain'

export interface ISudokuGameProps {
  storageKey?: string
  initialState?: Partial<ISudokuState> | Promise<Partial<ISudokuState>>
}

export const SudokuGame: React.FC<ISudokuGameProps> = props => {
  return (
    <SudokuContextProvider storageKey={props.storageKey} initialData={props.initialState}>
      <SudokuGameMain />
    </SudokuContextProvider>
  )
}

SudokuGame.propTypes = {
  storageKey: PropTypes.string.isRequired,
  initialState: PropTypes.any,
}
